#include <stdio.h>
#include <stdbool.h>

#define MAXN 10000

int main() {
    bool isPrime[MAXN + 1];
    for (int i = 0; i <= MAXN; ++i) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i <= MAXN; ++i) {
        if (isPrime[i]) {
            for (int j = i * i; j <= MAXN; j += i) isPrime[j] = false;
        }
    }
    int primes[1300];
    int pcnt = 0;
    for (int i = 2; i <= MAXN; ++i) if (isPrime[i]) primes[pcnt++] = i;

    int ans[MAXN + 1] = {0};
    for (int i = 0; i < pcnt; ++i) {
        for (int j = 0; j < pcnt; ++j) {
            int sum = primes[i] + 2 * primes[j];
            if (sum > MAXN) break;
            ++ans[sum];
        }
    }

    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        printf("%d\n", ans[N]);
    }
    return 0;
}

