    for (int i = 2; i <= MAXN; ++i) if (isPrime[i]) primes.push_back(i);
    vector<int> ans(MAXN + 1, 0);
    for (int p : primes) {
        for (int q : primes) {
            int sum = p + 2 * q;
            if (sum > MAXN) break;
            ++ans[sum];
        }
    }
    int T; cin >> T;
    while (T--) {
        int N; cin >> N;
        cout << ans[N] << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static final int MAXN = 10000;
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        boolean[] isPrime = new boolean[MAXN + 1];
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= MAXN; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= MAXN; j += i) isPrime[j] = false;
            }
        }
        List<Integer> primes = new ArrayList<>();
        for (int i = 2; i <= MAXN; i++) if (isPrime[i]) primes.add(i);
        int[] ans = new int[MAXN + 1];
        for (int p : primes) {
            for (int q : primes) {
                int sum = p + 2 * q;
                if (sum > MAXN) break;
                ans[sum]++;
            }
        }
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine().trim());
            sb.append(ans[N]).append('\n');
        }
        System.out.print(sb.toString());
    }
}

